import React, { useEffect, useState } from 'react';
import { useSelector } from 'react-redux';
import { toast } from 'react-toastify';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';
import { beneficiarySchema } from '../../schemas';
import { useFormik } from 'formik';

export default function ProfilePage() {
  const { user } = useSelector(s => s.auth);
  const [profile, setProfile] = useState(null);
  const [accounts, setAccounts] = useState([]);
  const [beneficiaries, setBeneficiaries] = useState([]);
  const [showBenForm, setShowBenForm] = useState(false);

  useEffect(() => {
    axiosInstance.get('/customers/profile/me').then(r => { setProfile(r.data.customer); setAccounts(r.data.accounts); });
    axiosInstance.get('/beneficiaries/my').then(r => setBeneficiaries(r.data.beneficiaries || []));
  }, []);

  const benFormik = useFormik({
    initialValues: { beneficiaryName: '', accountNumber: '', branch: '' },
    validationSchema: beneficiarySchema,
    onSubmit: async (values, { resetForm }) => {
      try {
        await axiosInstance.post('/beneficiaries', values);
        toast.success('Beneficiary submitted for approval');
        axiosInstance.get('/beneficiaries/my').then(r => setBeneficiaries(r.data.beneficiaries || []));
        resetForm(); setShowBenForm(false);
      } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
    }
  });

  const inp = { padding: '9px 12px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, width: '100%', boxSizing: 'border-box', marginBottom: 10 };
  const statusColor = { PENDING: '#f59e0b', ACTIVE: '#22c55e', REJECTED: '#ef4444' };

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 className="mb-4" style={{ color: '#1e293b' }}>👤 Profile</h2>
      </div>

      <div className="row g-4 align-items-start">
        {/* Personal Details */}
        <div className="col-12 col-md-6 col-lg-5">
          <div style={{ background: '#fff', borderRadius: 12, padding: 24, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
            <h3 className="mb-4">Personal Details</h3>
            {profile && [
              ['Customer ID', profile.customerId], ['Name', profile.name], ['Email', profile.email],
              ['Phone', profile.phone], ['Address', profile.address],
              ['Gov ID Type', profile.govIdType], ['Gov ID Number', profile.govIdNumber],
              ['Status', profile.status], ['Joined', new Date(profile.createdAt).toLocaleDateString('en-IN')]
            ].map(([lbl, val]) => (
              <div key={lbl} className="d-flex justify-content-between flex-wrap gap-1 py-2" style={{ borderBottom: '1px solid #f1f5f9' }}>
                <span style={{ color: '#64748b', fontSize: 13 }}>{lbl}</span>
                <span style={{ fontWeight: 600, fontSize: 13, wordBreak: 'break-all' }}>{val || '—'}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Accounts + Beneficiaries */}
        <div className="col-12 col-md-6 col-lg-7">
          {/* Accounts */}
          <div className="mb-4" style={{ background: '#fff', borderRadius: 12, padding: 24, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
            <h3 className="mb-3">My Accounts</h3>
            {accounts.map(a => (
              <div key={a.accountNumber} className="py-3" style={{ borderBottom: '1px solid #f1f5f9' }}>
                <div className="d-flex justify-content-between align-items-start flex-wrap gap-2">
                  <div>
                    <p style={{ margin: 0, fontFamily: 'monospace', fontSize: 13, color: '#3b82f6' }}>{a.accountNumber}</p>
                    <p style={{ margin: '2px 0 0', fontSize: 12, color: '#64748b' }}>{a.accountType}</p>
                  </div>
                  <div className="text-end">
                    <p style={{ margin: 0, fontWeight: 700 }}>₹{a.balance?.toLocaleString('en-IN')}</p>
                    <span style={{ fontSize: 11, color: statusColor[a.status] || '#94a3b8', fontWeight: 700 }}>{a.status}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Beneficiaries */}
          <div style={{ background: '#fff', borderRadius: 12, padding: 24, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
            <div className="d-flex justify-content-between align-items-center mb-3">
              <h3 className="mb-0">Beneficiaries</h3>
              <button onClick={() => setShowBenForm(!showBenForm)} className="btn btn-sm" style={{ padding: '6px 14px', borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 700, fontSize: 12 }}>+ Add</button>
            </div>
            {showBenForm && (
              <form onSubmit={benFormik.handleSubmit} className="mb-3 p-3" style={{ background: '#f8fafc', borderRadius: 8 }}>
                <input placeholder="Beneficiary Name" style={inp} {...benFormik.getFieldProps('beneficiaryName')} />
                <input placeholder="Account Number" style={inp} {...benFormik.getFieldProps('accountNumber')} />
                <input placeholder="Branch (optional)" style={inp} {...benFormik.getFieldProps('branch')} />
                <button type="submit" style={{ width: '100%', padding: '8px', borderRadius: 8, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>Submit</button>
              </form>
            )}
            {beneficiaries.map(b => (
              <div key={b.beneficiaryId} className="d-flex justify-content-between flex-wrap gap-2 py-2" style={{ borderBottom: '1px solid #f1f5f9' }}>
                <div>
                  <p style={{ margin: 0, fontWeight: 600, fontSize: 14 }}>{b.beneficiaryName}</p>
                  <p style={{ margin: '2px 0 0', fontFamily: 'monospace', fontSize: 12, color: '#64748b' }}>{b.accountNumber}</p>
                </div>
                <span style={{ fontSize: 11, fontWeight: 700, color: statusColor[b.status] || '#94a3b8' }}>{b.status}</span>
              </div>
            ))}
            {beneficiaries.length === 0 && !showBenForm && <p style={{ color: '#94a3b8', fontSize: 13, textAlign: 'center' }}>No beneficiaries added</p>}
          </div>
        </div>
      </div>
    </Layout>
  );
}
